  course: Course;
  deadlines: Deadline[];
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onAddDeadline: (deadline: Omit<Deadline, 'id'>) => void;
  onBack: () => void;
}

// Вспомогательный компонент TopBar (оставил тут для удобства)
const TopBar: React.FC<{ userName: string }> = ({ userName }) => {
  return (
    <div className="topbar">
      <div className="topbar__content">
        <h1 className="topbar__title">Course Details</h1>
        <div className="topbar__user">
          <span className="topbar__user-name">Welcome {userName}</span>
        </div>
      </div>
    </div>
  );
};

// Вспомогательный компонент DeadlineModal
const DeadlineModal: React.FC<{
  courses: Course[];
  preselectedCourseId: string;
  onSave: (deadline: Omit<Deadline, 'id'>) => void;
  onClose: () => void;
}> = ({ courses, preselectedCourseId, onSave, onClose }) => {
  const [taskName, setTaskName] = useState('');
  const [selectedCourseId, setSelectedCourseId] = useState(preselectedCourseId);
  const [dueDate, setDueDate] = useState('');
  const [type, setType] = useState('assignment');
  const [priority, setPriority] = useState('medium');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!taskName || !selectedCourseId || !dueDate) return;

    onSave({
      courseId: selectedCourseId,
      taskName,
      type: type as Deadline['type'],
      dueDate: new Date(dueDate),
      status: 'upcoming',
      priority: priority as Deadline['priority']
    });
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal__header">
          <h3 className="modal__title">Add New Deadline</h3>
          <button onClick={onClose} className="modal__close-btn">×</button>
        </div>
        <form onSubmit={handleSubmit} className="modal__form">
          <div className="form-group">
            <label className="form-label">Task Name</label>
            <input type="text" value={taskName} onChange={(e) => setTaskName(e.target.value)} className="form-input" required />
          </div>
          <div className="form-group">
            <label className="form-label">Course</label>
            <select value={selectedCourseId} onChange={(e) => setSelectedCourseId(e.target.value)} className="form-select">
              {courses.map(course => <option key={course.id} value={course.id}>{course.title}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Type</label>
            <select value={type} onChange={(e) => setType(e.target.value)} className="form-select">
              <option value="assignment">Assignment</option>
              <option value="quiz">Quiz</option>
              <option value="exam">Exam</option>
              <option value="project">Project</option>
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Due Date</label>
            <input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} className="form-input" required />
          </div>
          <div className="modal__actions">
            <button type="button" className="btn btn--secondary" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn--primary">Save</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export function CourseDetailsPage({
  currentPage,
  course,
  deadlines,
  onNavigate,
  onLogout,
  onAddDeadline,
  onBack
}: CourseDetailsPageProps) {
  const [showAddModal, setShowAddModal] = useState(false);

  const getPriorityClass = (p: string) => `badge badge--${p}`;
  const getStatusClass = (s: string) => `badge badge--${s}`;
  const getTypeIcon = (t: string) => ({ assignment: '📝', quiz: '❓', exam: '📋', project: '💼' }[t] || '📄');

  const upcoming = deadlines.filter(d => d.status === 'upcoming').length;
  const overdue = deadlines.filter(d => d.status === 'overdue').length;
  const completed = deadlines.filter(d => d.status === 'completed').length;

  return (
    <div className="course-details-page">
      <Sidebar currentPage={currentPage} onNavigate={onNavigate} onLogout={onLogout} />

      <div className="main-content">
        <TopBar userName="Alex" />

        <main className="content">
          <button onClick={onBack} className="back-btn">← Back to Courses</button>

          <div className="course-header">
            <div className="course-header__banner" style={{ backgroundColor: course.color }}>
              <div className="course-header__overlay" />
              <div className="course-header__info">
                <div className="course-header__left">
                  <h1 className="course-header__title">{course.title}</h1>
                  <div className="course-header__meta">
                    <span className="course-header__meta-item">👤 {course.instructor}</span>
                    <span className="course-header__meta-item">⏰ {course.semester}</span>
                  </div>
                </div>
                <button onClick={() => setShowAddModal(true)} className="btn btn--add-deadline">+ Add Deadline</button>
              </div>
            </div>

            <div className="course-stats">
              <div className="course-stats__item">
                <div className="course-stats__value">{upcoming}</div>
                <div className="course-stats__label">Upcoming</div>
              </div>
              <div className="course-stats__item course-stats__item--border">
                <div className="course-stats__value">{overdue}</div>
                <div className="course-stats__label">Overdue</div>
              </div>
              <div className="course-stats__item">
                <div className="course-stats__value">{completed}</div>
                <div className="course-stats__label">Completed</div>
              </div>
            </div>
          </div>

          <div className="deadlines-section">
            <div className="deadlines-section__header">
              <h2 className="deadlines-section__title">Course Deadlines</h2>
            </div>
            <div className="deadlines-table-container">
              <table className="deadlines-table">
                <thead>
                  <tr>
                    <th>Task</th><th>Type</th><th>Due Date</th><th>Status</th><th>Priority</th>
                  </tr>
                </thead>
                <tbody>
                  {deadlines.map(d => (
                    <tr key={d.id}>
                      <td>{d.taskName}</td>
                      <td>{getTypeIcon(d.type)} {d.type}</td>
                      <td>{d.dueDate.toLocaleDateString()}</td>
                      <td><span className={getStatusClass(d.status)}>{d.status}</span></td>
                      <td><span className={getPriorityClass(d.priority)}>{d.priority}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </main>
      </div>

      {showAddModal && (
        <DeadlineModal courses={[course]} preselectedCourseId={course.id} onSave={onAddDeadline} onClose={() => setShowAddModal(false)} />
      )}
    </div>
  );
}
